/**
 * Location of an attacker.
 */
export interface AttackerLocation {
    /**
     * City of the attacker.
     */
    city?: string;
    /**
     * The country of the attacker.
     */
    country?: string;
    /**
     * The country code of the country of the attacker, according to the ISO 3166-1 Alpha-2 standard.
     */
    countryCode?: string;
}
